import{_ as t,o as a,c as s,an as n}from"./chunks/framework.ubcH7j8_.js";const g=JSON.parse('{"title":"Messaging (Flash)","description":"","frontmatter":{},"headers":[],"relativePath":"services/messaging.md","filePath":"services/messaging.md","lastUpdated":1773164166000}'),r={name:"services/messaging.md"};function i(o,e,l,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="messaging-flash" tabindex="-1">Messaging (Flash) <a class="header-anchor" href="#messaging-flash" aria-label="Permalink to &quot;Messaging (Flash)&quot;">​</a></h1><blockquote><p><strong>Status:</strong> Active | <strong>Port:</strong> 4222, 8222 | <strong>Profile:</strong> think, reason, ultra-instinct</p></blockquote><p>The <code>arc-messaging</code> service (Flash) is the platform message broker built on NATS. It carries low-latency, ephemeral messages between platform services and agent workers — <strong>the fast synchronous layer</strong> of the A.R.C. messaging system.</p><p>For durable event streaming with persistence and replay, see <a href="/arc-platform/docs/services/streaming.html">Streaming (Dr. Strange)</a>.</p><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Image</td><td><code>ghcr.io/arc-framework/arc-messaging:latest</code></td></tr><tr><td>Port(s)</td><td>4222 (client), 8222 (monitoring)</td></tr><tr><td>Health</td><td><code>http://localhost:8222/healthz</code></td></tr><tr><td>Profile(s)</td><td>think, reason, ultra-instinct (core)</td></tr></tbody></table><h2 id="make-targets" tabindex="-1">Make Targets <a class="header-anchor" href="#make-targets" aria-label="Permalink to &quot;Make Targets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Target</th><th>Description</th></tr></thead><tbody><tr><td><code>make messaging-up</code></td><td>Start the service</td></tr><tr><td><code>make messaging-down</code></td><td>Stop the service</td></tr><tr><td><code>make messaging-health</code></td><td>Check health</td></tr><tr><td><code>make messaging-logs</code></td><td>Tail service logs</td></tr></tbody></table><h2 id="when-to-use-messaging-flash" tabindex="-1">When to Use Messaging (Flash) <a class="header-anchor" href="#when-to-use-messaging-flash" aria-label="Permalink to &quot;When to Use Messaging (Flash)&quot;">​</a></h2><p>Messaging (Flash) is ideal for <strong>synchronous, ephemeral</strong> communication:</p><table tabindex="0"><thead><tr><th>Use Case</th><th>Messaging (Flash)</th><th>Streaming (Dr. Strange)</th></tr></thead><tbody><tr><td>Agent asks another agent to act</td><td>✅</td><td>❌</td></tr><tr><td>Distribute work across workers</td><td>✅ (queue groups)</td><td>❌</td></tr><tr><td>Request/reply pattern</td><td>✅</td><td>❌</td></tr><tr><td>Heartbeat / presence</td><td>✅</td><td>❌</td></tr><tr><td>Event sourcing / audit log</td><td>❌</td><td>✅</td></tr><tr><td>Replay historical events</td><td>❌</td><td>✅</td></tr><tr><td>Cross-service event distribution</td><td>❌</td><td>✅</td></tr></tbody></table><p><strong>Rule of thumb:</strong> If you need the other side to respond now, use <code>arc-messaging</code>. If you need a durable record that can be replayed later, use <code>arc-streaming</code>.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>Sub-millisecond latency</strong> — in-memory only, no disk I/O</li><li><strong>Pub/sub</strong> — fan-out to multiple subscribers</li><li><strong>Request/reply</strong> — synchronous RPC over messaging</li><li><strong>Queue groups</strong> — load-balanced work distribution</li><li><strong>Lightweight</strong> — minimal CPU and RAM footprint</li></ul><h2 id="connection" tabindex="-1">Connection <a class="header-anchor" href="#connection" aria-label="Permalink to &quot;Connection&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Default client URL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nats://localhost:4222</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Monitoring dashboard</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8222</span></span></code></pre></div><h2 id="patterns" tabindex="-1">Patterns <a class="header-anchor" href="#patterns" aria-label="Permalink to &quot;Patterns&quot;">​</a></h2><h3 id="pub-sub-fan-out" tabindex="-1">Pub/Sub (Fan-out) <a class="header-anchor" href="#pub-sub-fan-out" aria-label="Permalink to &quot;Pub/Sub (Fan-out)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Publisher → Topic → Subscriber A</span></span>
<span class="line"><span>                  → Subscriber B</span></span>
<span class="line"><span>                  → Subscriber C</span></span></code></pre></div><h3 id="request-reply-rpc" tabindex="-1">Request/Reply (RPC) <a class="header-anchor" href="#request-reply-rpc" aria-label="Permalink to &quot;Request/Reply (RPC)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent A → request(topic, payload) → Agent B</span></span>
<span class="line"><span>Agent A ←    reply(result)        ←</span></span></code></pre></div><h3 id="queue-group-load-balancing" tabindex="-1">Queue Group (Load Balancing) <a class="header-anchor" href="#queue-group-load-balancing" aria-label="Permalink to &quot;Queue Group (Load Balancing)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Job Queue → Worker 1</span></span>
<span class="line"><span>          → Worker 2 (only one receives each message)</span></span>
<span class="line"><span>          → Worker 3</span></span></code></pre></div><h2 id="reasoner-integration" tabindex="-1">Reasoner Integration <a class="header-anchor" href="#reasoner-integration" aria-label="Permalink to &quot;Reasoner Integration&quot;">​</a></h2><p>The Reasoner service (Sherlock) uses <code>arc-messaging</code> (Flash) as its primary async trigger. See <a href="/arc-platform/docs/services/reasoner.html">Reasoner</a> for the full NATS subject schema used by the platform.</p>`,25)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
